// 当 Mode 为 "Run Once for All Items" 时，输入是一个名为 $input.all() 的数组
const allItems = $input.all();

// 处理每一项数据（通常 Chat Trigger 只有 1 个 Item）
return allItems.map(item => {
  const newBinary = {};

  // 获取当前 item 中所有的二进制键名 (例如: data0, data1)
  const binaryKeys = Object.keys(item.binary || {});

  // 按照你的要求，提取前 3 张并重命名
  binaryKeys.slice(0, 3).forEach((key, index) => {
    newBinary[`image_${index}`] = item.binary[key];
  });

  // 返回符合 n8n 规范的结构
  return {
    json: item.json,
    binary: newBinary
  };
});

const items = $input.all();

const toStr = (v) => (v == null ? '' : String(v).trim());

const getChatInput = () => {
  try {
    const n = $('Code in JavaScript2').first();
    return toStr(n?.json?.chatInput);
  } catch (_) {
    return '';
  }
};

const chatInput = getChatInput();
const base64_list = [];

for (let i = 0; i < items.length; i++) {
  const bin = items[i].binary || {};
  const keys = Object.keys(bin).filter(k =>
    k.startsWith('image') || k.startsWith('data') || k.startsWith('file') || k.startsWith('webp')
  );

  for (const key of keys) {
    const buf = await this.helpers.getBinaryDataBuffer(i, key);
    const b64 = Buffer.isBuffer(buf) ? buf.toString('base64') : Buffer.from(buf).toString('base64');
    if (b64) base64_list.push(b64);
  }
}

return [{
  json: {
    chatInput,
    base64_list
  }
}];

