        },
        {
          "text": "以下是用户提供的产品背景文字信息：\n{{ $json.chatInput }}"
        },
        {{ $json.base64_list.map(base64 => `{
          "inline_data": {
            "mime_type": "image/webp",
            "data": "${base64}"
          }
        }`).join(',') }}
      ]
    }
  ]
}

