const items = $input.all();

const toStr = (v) => (v == null ? '' : String(v).trim());

const collectPrompts = () => {
  const out = [];
  for (const it of items) {
    let s = toStr(it.json?.candidates?.[0]?.content?.parts?.[0]?.text);
    if (!s) continue;

    s = s.replace(/^```json\s*\[?\n?/, '')
         .replace(/\n?\]?\s*```$/, '')
         .trim();

    s = s.replace(/\\n/g, ' ')
         .replace(/\n/g, ' ')
         .replace(/\/n/g, ' ')
         .replace(/\\/g, '')
         .replace(/\//g, ' ');

    s = s.replace(/\"/g, '');

    s = s.replace(/\s+/g, ' ').trim();

    s = s.replace(/[!\"$%&'()*+\-./:;<=>?@[\\\]^_`{|}~，。；：！？、“”‘’（）《》【】…—]/g, ',');
    s = s.replace(/\s*,\s*/g, ',').replace(/,+/g, ',').replace(/^,|,$/g, '');

    out.push(s);
  }
  return Array.from(new Set(out));
};

const prompts = collectPrompts();

return [{
  json: {
    prompt: prompts[0] || ""
  }
}];

